4712   /// Gets the live-in VPIRValue for \p V or adds a new live-in (if none exists
4713   ///  yet) for \p V.
4714   VPIRValue *getOrAddLiveIn(Value *V) {
4715     assert(V && "Trying to get or add the VPIRValue of a null Value");
4716     auto [It, Inserted] = LiveIns.try_emplace(V);
4717     if (Inserted) {
4718       if (auto *CI = dyn_cast<ConstantInt>(V))
4719         It->second = new VPConstantInt(CI);
4720       else
4721         It->second = new VPIRValue(V);
4722     }
4723 
4724     assert(isa<VPIRValue>(It->second) &&
4725            "Only VPIRValues should be in mapping");
4726     return It->second;
4727   }
4728   VPIRValue *getOrAddLiveIn(VPIRValue *V) {
4729     assert(V && "Trying to get or add the VPIRValue of a null VPIRValue");
4730     return getOrAddLiveIn(V->getValue());
4731   }
4732 
4733   /// Return a VPIRValue wrapping i1 true.
4734   VPIRValue *getTrue() { return getConstantInt(1, 1); }
4735 
4736   /// Return a VPIRValue wrapping i1 false.
4737   VPIRValue *getFalse() { return getConstantInt(1, 0); }
4738 
4739   /// Return a VPIRValue wrapping a ConstantInt with the given type and value.
4740   VPIRValue *getConstantInt(Type *Ty, uint64_t Val, bool IsSigned = false) {
4741     return getOrAddLiveIn(ConstantInt::get(Ty, Val, IsSigned));
4742   }
