4494   /// Holds the VFs applicable to this VPlan.
4495   SmallSetVector<ElementCount, 2> VFs;
4496 
4497   /// Holds the UFs applicable to this VPlan. If empty, the VPlan is valid for
4498   /// any UF.
4499   SmallSetVector<unsigned, 2> UFs;
4500 
4501   /// Holds the name of the VPlan, for printing.
4502   std::string Name;
4503 
4504   /// Represents the trip count of the original loop, for folding
4505   /// the tail.
4506   VPValue *TripCount = nullptr;
4507 
4508   /// Represents the backedge taken count of the original loop, for folding
4509   /// the tail. It equals TripCount - 1.
4510   VPSymbolicValue *BackedgeTakenCount = nullptr;
4511 
4512   /// Represents the vector trip count.
