1022                                     vp_depth_first_shallow(getEntry())),
1023                                 [&VF, &Ctx](VPBasicBlock *VPBB) {
1024                                   return !VPBB->cost(VF, Ctx).isValid();
1025                                 }))
1026     return InstructionCost::getInvalid();
1027 
1028   return Cost;
