1369      << Indent << "label=\""
1370      << DOT::EscapeString(Region->isReplicator() ? "<xVFxUF> " : "<x1> ")
1371      << DOT::EscapeString(Region->getName()) << "\"\n";
1372   // Dump the blocks of the region.
